#!/usr/bin/env python3
"""
GROMACS Gibbs Free Energy Landscape Visualization Script

This script generates high-quality 3D surface and 2D contour plots from
free energy landscape data generated by GROMACS SHAM analysis.

Usage:
    python plot_gibbs_landscape.py --input free_energy_landscape.txt
    python plot_gibbs_landscape.py --input data.txt --output plot.svg --smoothing 2.0
"""

import argparse
import numpy as np
import matplotlib.pyplot as plt
from matplotlib import cm
from scipy.ndimage import gaussian_filter
from scipy.interpolate import griddata
import os
import sys


def load_energy_data(filename):
    """Load free energy data from text file."""
    try:
        data = np.loadtxt(filename)
        if data.shape[1] < 3:
            raise ValueError("Data file must contain at least 3 columns (x, y, z)")
        return data[:, 0], data[:, 1], data[:, 2]
    except Exception as e:
        print(f"Error loading data from {filename}: {e}")
        sys.exit(1)


def interpolate_data(x, y, z, nbins=100, method='cubic'):
    """Interpolate scattered data onto regular grid."""
    xi = np.linspace(x.min(), x.max(), nbins)
    yi = np.linspace(y.min(), y.max(), nbins)
    xi_grid, yi_grid = np.meshgrid(xi, yi)
    
    zi = griddata((x, y), z, (xi_grid, yi_grid), method=method)
    return xi_grid, yi_grid, zi, xi, yi


def smooth_data(zi, sigma=1.5):
    """Apply Gaussian smoothing to the interpolated data."""
    return gaussian_filter(zi, sigma=sigma)


def find_global_minimum(xi_grid, yi_grid, zi_smooth):
    """Find the global minimum in the free energy landscape."""
    min_idx = np.unravel_index(np.nanargmin(zi_smooth), zi_smooth.shape)
    min_x = xi_grid[min_idx[0], min_idx[1]]
    min_y = yi_grid[min_idx[0], min_idx[1]]
    min_z = zi_smooth[min_idx[0], min_idx[1]]
    return min_x, min_y, min_z


def create_visualization(xi_grid, yi_grid, zi_smooth, min_x, min_y, min_z, 
                        title="Gibbs Free Energy Surface", output_file=None, 
                        format='svg', dpi=300):
    """Create the final visualization with 3D surface and 2D contour plots."""
    
    # Set up the figure
    fig = plt.figure(figsize=(14, 6))
    cmap = plt.colormaps["RdYlBu_r"]
    
    # 3D Surface plot
    ax1 = fig.add_subplot(1, 2, 1, projection='3d')
    surf = ax1.plot_surface(xi_grid, yi_grid, zi_smooth, 
                           cmap=cmap, edgecolor='none', antialiased=True)
    ax1.scatter(min_x, min_y, min_z, color='black', s=60, label="Global Minimum")
    ax1.set_xlabel("PC1 (nm)")
    ax1.set_ylabel("PC2 (nm)")
    ax1.set_zlabel("G (kJ/mol)")
    ax1.set_title(title, fontsize=14)
    ax1.view_init(elev=20, azim=-30)
    ax1.legend()
    ax1.grid(False)
    
    # Set z-axis ticks
    z_max = np.nanmax(zi_smooth)
    z_ticks = np.arange(0, z_max + 2, 2)
    ax1.set_zticks(z_ticks)
    
    # Add colorbar for 3D plot
    fig.colorbar(surf, ax=ax1, shrink=0.6, label="G (kJ/mol)")
    
    # 2D Contour plot
    ax2 = fig.add_subplot(1, 2, 2)
    contour = ax2.contourf(xi_grid, yi_grid, zi_smooth, levels=50, cmap=cmap)
    ax2.scatter(min_x, min_y, color='black', s=40, label="Global Minimum")
    ax2.set_xlabel("PC1 (nm)")
    ax2.set_ylabel("PC2 (nm)")
    ax2.set_title(title, fontsize=14)
    ax2.legend()
    
    # Add colorbar for contour plot
    fig.colorbar(contour, ax=ax2, label="G (kJ/mol)")
    
    # Adjust layout and save
    plt.tight_layout()
    
    if output_file:
        # Determine format from file extension if not specified
        if format == 'auto':
            format = output_file.split('.')[-1].lower()
        
        plt.savefig(output_file, format=format, dpi=dpi, bbox_inches='tight')
        print(f"Plot saved as: {output_file}")
    else:
        plt.show()
    
    return fig


def main():
    parser = argparse.ArgumentParser(
        description="Generate Gibbs Free Energy Landscape visualization",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  python plot_gibbs_landscape.py --input free_energy_landscape.txt
  python plot_gibbs_landscape.py --input data.txt --output plot.png --format png
  python plot_gibbs_landscape.py --input data.txt --smoothing 2.0 --grid-size 150
        """
    )
    
    parser.add_argument('--input', '-i', required=True,
                       help='Input free energy landscape data file (3-column: x, y, z)')
    parser.add_argument('--output', '-o', default=None,
                       help='Output file name (default: show plot)')
    parser.add_argument('--title', '-t', default="Gibbs Free Energy Surface",
                       help='Plot title (default: "Gibbs Free Energy Surface")')
    parser.add_argument('--format', '-f', default='auto',
                       choices=['auto', 'svg', 'png', 'pdf', 'eps'],
                       help='Output format (default: auto-detect from filename)')
    parser.add_argument('--dpi', type=int, default=300,
                       help='Output resolution in DPI (default: 300)')
    parser.add_argument('--smoothing', '-s', type=float, default=1.5,
                       help='Gaussian smoothing sigma (default: 1.5)')
    parser.add_argument('--grid-size', '-g', type=int, default=100,
                       help='Interpolation grid size (default: 100)')
    parser.add_argument('--interpolation', default='cubic',
                       choices=['linear', 'nearest', 'cubic'],
                       help='Interpolation method (default: cubic)')
    
    args = parser.parse_args()
    
    # Check if input file exists
    if not os.path.exists(args.input):
        print(f"Error: Input file '{args.input}' not found")
        sys.exit(1)
    
    print(f"Loading data from: {args.input}")
    
    # Load and process data
    x, y, z = load_energy_data(args.input)
    print(f"Loaded {len(x)} data points")
    
    # Interpolate data
    print(f"Interpolating data onto {args.grid_size}x{args.grid_size} grid...")
    xi_grid, yi_grid, zi, xi, yi = interpolate_data(x, y, z, args.grid_size, args.interpolation)
    
    # Apply smoothing
    print(f"Applying Gaussian smoothing (sigma={args.smoothing})...")
    zi_smooth = smooth_data(zi, args.smoothing)
    
    # Find global minimum
    min_x, min_y, min_z = find_global_minimum(xi_grid, yi_grid, zi_smooth)
    print(f"Global minimum found at: PC1={min_x:.3f}, PC2={min_y:.3f}, G={min_z:.3f} kJ/mol")
    
    # Create visualization
    print("Generating visualization...")
    fig = create_visualization(xi_grid, yi_grid, zi_smooth, min_x, min_y, min_z,
                              title=args.title, output_file=args.output, 
                              format=args.format, dpi=args.dpi)
    
    print("Visualization completed successfully!")


if __name__ == "__main__":
    main()
